    error_t _handleErrorSerialize(uint8_t action, uint16_t error_mask_1, bool error_mask_1_present, uint8_t length, const uint32_t *error_mask_2, uint32_t *payload, uint8_t *payload_length)
    {
        // Check request parameters
        CHECK_PARAM_GREATER(action, 3);
        CHECK_PARAM_GREATER_IF_PRESENT(error_mask_1, 511, error_mask_1_present);
        CHECK_PARAM_GREATER(length, 8);

        // Check array pointers
        if ((NULL == error_mask_2) && (length != 0))
        {
            errorLog("Array is NULL but length is not 0");
            return IFXRFE_E_MISSING_PARAMETER;
        }
        // Transform request parameters
        *payload_length = 0;

        payload[*payload_length] = (action & 0x3);
        (*payload_length)++;

        payload[*payload_length] = (error_mask_1_present) ? (error_mask_1 & 0x1FF) : 0;
        *payload_length += (error_mask_1_present) ? 1 : 0;

        memcpy(&payload[*payload_length], error_mask_2, length * sizeof(uint32_t));
        *payload_length += length;

        return IFXRFE_E_SUCCESS;
    }

    error_t _handleErrorParse(const uint32_t *payload, uint8_t payload_length, IfxRfe_handleErrorResult_t *res)
    {
        if (payload_length < 1)  //only check the length of the mandatory fields
        {
            return IFXRFE_E_UNEXPECTED_VALUE;
        }
        if (NULL == res)
        {
            return IFXRFE_E_SUCCESS;  //nothing to parse
        }
        res->failure_ind_m             = (payload[0] >> 1) & 0x1;
        res->failure_ind_a             = (payload[0] >> 2) & 0x1;
        res->failure_ind_b             = (payload[0] >> 3) & 0x1;
        res->failure_ind_c             = (payload[0] >> 4) & 0x1;
        res->optional_fields_available = false;
        if (payload_length > 1)  //if there are optional fields available, parse them
        {
            res->optional_fields_available = true;
            res->error_status_1            = payload[1] & 0x1FF;
            uint8_t arrayLength            = payload_length - 2;
            res->length                    = arrayLength;
            memcpy(res->error_status_2, &payload[2], arrayLength * sizeof(uint32_t));
        }

        return IFXRFE_E_SUCCESS;
    }

