    error_t _configureDiosSerialize(uint16_t config_mask_ext, uint8_t clkmcu_drive_strength, uint8_t clkmcu_driver_config, uint8_t clkmcu_pull_config, uint8_t dmux1_drive_strength, uint8_t dmux1_driver_config, uint8_t dmux1_pull_config, uint8_t dmux2_drive_strength, uint8_t dmux2_driver_config, uint8_t dmux2_pull_config, uint8_t dmux3_drive_strength, uint8_t dmux3_driver_config, uint8_t dmux3_pull_config, uint8_t so_drive_strength, uint8_t so_driver_config, uint8_t so_pull_config, uint8_t rft_drive_strength, uint8_t rft_driver_config, uint8_t rft_pull_config, uint32_t *payload, uint8_t *payload_length)
    {
        // Check request parameters
        CHECK_PARAM_GREATER(config_mask_ext, 2047);
        CHECK_PARAM_GREATER(clkmcu_drive_strength, 4);
        CHECK_PARAM_GREATER(clkmcu_driver_config, 2);
        CHECK_PARAM_GREATER(clkmcu_pull_config, 3);
        CHECK_PARAM_GREATER(dmux1_drive_strength, 4);
        CHECK_PARAM_GREATER(dmux1_driver_config, 2);
        CHECK_PARAM_GREATER(dmux1_pull_config, 3);
        CHECK_PARAM_GREATER(dmux2_drive_strength, 4);
        CHECK_PARAM_GREATER(dmux2_driver_config, 2);
        CHECK_PARAM_GREATER(dmux2_pull_config, 3);
        CHECK_PARAM_GREATER(dmux3_drive_strength, 4);
        CHECK_PARAM_GREATER(dmux3_driver_config, 2);
        CHECK_PARAM_GREATER(dmux3_pull_config, 3);
        CHECK_PARAM_GREATER(so_drive_strength, 4);
        CHECK_PARAM_GREATER(so_driver_config, 2);
        CHECK_PARAM_GREATER(so_pull_config, 3);
        CHECK_PARAM_GREATER(rft_drive_strength, 4);
        CHECK_PARAM_GREATER(rft_driver_config, 2);
        CHECK_PARAM_GREATER(rft_pull_config, 3);

        // Transform request parameters
        payload[0] = (config_mask_ext & 0x7FF);
        payload[1] = (clkmcu_drive_strength & 0x7);
        payload[1] |= ((clkmcu_driver_config & 0x3) << 3);
        payload[1] |= ((clkmcu_pull_config & 0x7) << 5);
        payload[1] |= ((dmux1_drive_strength & 0x7) << 8);
        payload[1] |= ((dmux1_driver_config & 0x3) << 11);
        payload[1] |= ((dmux1_pull_config & 0x7) << 13);
        payload[1] |= ((dmux2_drive_strength & 0x7) << 16);
        payload[1] |= ((dmux2_driver_config & 0x3) << 19);
        payload[1] |= ((dmux2_pull_config & 0x7) << 21);
        payload[1] |= ((dmux3_drive_strength & 0x7) << 24);
        payload[1] |= ((dmux3_driver_config & 0x3) << 27);
        payload[1] |= ((dmux3_pull_config & 0x7) << 29);
        payload[2] = (so_drive_strength & 0x7);
        payload[2] |= ((so_driver_config & 0x3) << 3);
        payload[2] |= ((so_pull_config & 0x7) << 5);
        payload[2] |= ((rft_drive_strength & 0x7) << 8);
        payload[2] |= ((rft_driver_config & 0x3) << 11);
        payload[2] |= ((rft_pull_config & 0x7) << 13);
        payload[3] = 0;

        *payload_length = 4;

        return IFXRFE_E_SUCCESS;
    }

